import{_ as t,o as n,c as r,a2 as e}from"./chunks/framework.CHeM0PsO.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"gm/dashboard-keuangan.md","filePath":"gm/dashboard-keuangan.md","lastUpdated":1784467494000}'),d={name:"gm/dashboard-keuangan.md"};function i(s,a,o,g,l,h){return n(),r("div",null,[...a[0]||(a[0]=[e('<h2 id="bab-7-dashboard-tab-1-—-keuangan-ringkasan-kpi" tabindex="-1">BAB 7: DASHBOARD TAB 1 — KEUANGAN &amp; RINGKASAN KPI <a class="header-anchor" href="#bab-7-dashboard-tab-1-—-keuangan-ringkasan-kpi" aria-label="Permalink to &quot;BAB 7: DASHBOARD TAB 1 — KEUANGAN &amp; RINGKASAN KPI&quot;">​</a></h2><p>Ini adalah layar pertama yang Anda lihat setelah login. Fungsinya: <strong>dalam 10 detik, Anda sudah tahu kondisi kafe</strong>.</p><h3 id="_7-1-pengaturan-filter-bagian-atas" tabindex="-1">7.1 Pengaturan Filter (Bagian Atas) <a class="header-anchor" href="#_7-1-pengaturan-filter-bagian-atas" aria-label="Permalink to &quot;7.1 Pengaturan Filter (Bagian Atas)&quot;">​</a></h3><p>Sebelum data muncul, Anda perlu memilih:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Fungsi</th></tr></thead><tbody><tr><td><strong>Tanggal Mulai &amp; Selesai</strong></td><td>Rentang waktu data yang ingin dilihat</td></tr><tr><td><strong>Outlet</strong></td><td>Perintis, Dg Tata, atau Semua</td></tr><tr><td><strong>Tombol &quot;Simpan &amp; Tarik Analisis&quot;</strong></td><td>Memerintahkan sistem menarik data dari database</td></tr></tbody></table><h3 id="_7-2-mode-waktu-otomatis-smart-briefing-mode" tabindex="-1">7.2 Mode Waktu Otomatis (Smart Briefing Mode) <a class="header-anchor" href="#_7-2-mode-waktu-otomatis-smart-briefing-mode" aria-label="Permalink to &quot;7.2 Mode Waktu Otomatis (Smart Briefing Mode)&quot;">​</a></h3><p>Sistem secara cerdas mendeteksi berapa hari rentang waktu yang Anda pilih, dan menyesuaikan gaya analisis:</p><table tabindex="0"><thead><tr><th>Lencana Mode</th><th>Rentang</th><th>Fokus Analisis</th></tr></thead><tbody><tr><td><strong>MODE OPERASIONAL (Biru)</strong></td><td>≤ 7 Hari</td><td>Evaluasi harian, deteksi anomali cuaca &amp; staf</td></tr><tr><td><strong>MODE TAKTIS (Ungu)</strong></td><td>8 – 95 Hari</td><td>Tren mingguan/bulanan, kinerja SPV</td></tr><tr><td><strong>MODE STRATEGIS (Ungu Tua)</strong></td><td>&gt; 95 Hari</td><td>Strategi makro bisnis, pertumbuhan tahunan. Beberapa modul detail otomatis disembunyikan agar data tidak bising</td></tr></tbody></table><h3 id="_7-3-ai-summary-kotak-warna-di-bagian-atas" tabindex="-1">7.3 AI Summary (Kotak Warna di Bagian Atas) <a class="header-anchor" href="#_7-3-ai-summary-kotak-warna-di-bagian-atas" aria-label="Permalink to &quot;7.3 AI Summary (Kotak Warna di Bagian Atas)&quot;">​</a></h3><p>Kotak ini adalah <strong>kesimpulan eksekutif instan</strong> yang dihasilkan mesin AI. Warna kotak menunjukkan tingkat urgensi:</p><table tabindex="0"><thead><tr><th>Warna</th><th>Artinya</th><th>Contoh Pesan</th></tr></thead><tbody><tr><td><strong>Hijau</strong></td><td>Semuanya aman</td><td>&quot;Momen Emas: Peluang mencetak rekor omset&quot;</td></tr><tr><td><strong>Biru</strong></td><td>Normal, tidak ada anomali</td><td>&quot;Kinerja stabil tanpa anomali&quot;</td></tr><tr><td><strong>Kuning</strong></td><td>Ada peringatan, perlu perhatian</td><td>&quot;Trafik padat, daya beli rendah (Event + Tanggal Tua)&quot;</td></tr><tr><td><strong>Merah</strong></td><td>Kritis, butuh tindakan segera</td><td>&quot;Batas Kelelahan Tim tercapai&quot; atau &quot;Prediksi staf resign mendadak&quot;</td></tr></tbody></table><blockquote><p><strong>Penting:</strong> Pesan AI ini bukan sekadar teks acak. Sistem menjalankan <strong>4 algoritma berbeda</strong> yang memeriksa silang antara omset, kebersihan, cuaca, kehadiran staf, dan event lokal. Penjelasan detail ada di BAB 10.</p></blockquote><h3 id="_7-4-total-omset-target" tabindex="-1">7.4 Total Omset &amp; Target <a class="header-anchor" href="#_7-4-total-omset-target" aria-label="Permalink to &quot;7.4 Total Omset &amp; Target&quot;">​</a></h3><p>Kotak hitam elegan yang menampilkan:</p><table tabindex="0"><thead><tr><th>Angka</th><th>Sumber Data</th><th>Cara Membaca</th></tr></thead><tbody><tr><td><strong>Total Omset (Rp)</strong></td><td>Penjumlahan Omset Shift 1 + Shift 2 dari semua laporan harian</td><td>Uang riil yang masuk pada periode yang Anda pilih</td></tr><tr><td><strong>Tren MoM (±%)</strong></td><td>Perbandingan dengan bulan lalu</td><td>Lencana kecil hijau (naik) atau merah (turun) di sebelah angka omset</td></tr><tr><td><strong>Target Omset (Rp) + Bar</strong></td><td>Dari Pengaturan Parameter SPV</td><td>Bar hijau bergerak proporsional 0-100%</td></tr><tr><td><strong>YTD Trajectory (Rp &amp; %)</strong></td><td>Akumulasi 1 Januari s/d hari ini vs Target Tahunan</td><td>Menunjukkan apakah bisnis on-track untuk mencapai target tahun ini. Target tahunan diatur oleh Anda di <strong>Pengaturan GM</strong></td></tr></tbody></table><h3 id="_7-5-metrik-transaksi-grafik" tabindex="-1">7.5 Metrik Transaksi &amp; Grafik <a class="header-anchor" href="#_7-5-metrik-transaksi-grafik" aria-label="Permalink to &quot;7.5 Metrik Transaksi &amp; Grafik&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Komponen</th><th>Sumber Data</th><th>Cara Membaca</th></tr></thead><tbody><tr><td><strong>Total Transaksi</strong></td><td>Total struk dari Fase 2</td><td>Jumlah pelanggan yang berhasil dilayani</td></tr><tr><td><strong>Average Ticket Size (ATS)</strong></td><td><code>Total Omset ÷ Total Transaksi</code></td><td>Rata-rata belanja per pelanggan. Semakin besar = semakin pintar staf membujuk pelanggan belanja lebih</td></tr><tr><td><strong>Trend Line Chart</strong></td><td>Omset per hari (garis waktu)</td><td>Lihat di tanggal berapa omset anjlok atau meroket</td></tr><tr><td><strong>Day of Week (Bar Chart)</strong></td><td>Rata-rata omset per nama hari (Senin, Selasa, dst.)</td><td><strong>Hari Terlemah</strong> = target promo. <strong>Hari Terkuat</strong> = siapkan staf penuh</td></tr></tbody></table><blockquote><p>Di bawah grafik Day of Week, terdapat <strong>Rekomendasi AI</strong> berupa 3 pilar saran otomatis (SDM, Marketing, Maintenance) yang menggunakan nama hari terlemah Anda.</p></blockquote><h3 id="_7-6-ringkasan-4-kpi-utama" tabindex="-1">7.6 Ringkasan 4 KPI Utama <a class="header-anchor" href="#_7-6-ringkasan-4-kpi-utama" aria-label="Permalink to &quot;7.6 Ringkasan 4 KPI Utama&quot;">​</a></h3><p>Empat kotak besar yang menampilkan detak jantung bisnis Anda:</p><table tabindex="0"><thead><tr><th>Kotak</th><th>Sumber Data</th><th>Kapan Warna Berubah Merah</th></tr></thead><tbody><tr><td><strong>SOP Keramahan</strong></td><td>Rata-rata dari audit SPV harian</td><td>Jika &lt; 90%</td></tr><tr><td><strong>Target Penjualan</strong></td><td>Omset Aktual vs Target</td><td>Jika aktual di bawah target</td></tr><tr><td><strong>Komplain Bulanan</strong></td><td>Hitungan form komplain</td><td>Jika &gt; 2 komplain sebulan</td></tr><tr><td><strong>Turnover Barista</strong></td><td>Form evaluasi bulanan SPV</td><td>Jika &gt; 1 staf keluar per kuartal</td></tr></tbody></table><p>Di atas 4 kotak ini terdapat <strong>Skor Operasional (0-100)</strong> dengan label EXCELLENT / GOOD / ATTENTION / CRITICAL. Skor ini dihitung dari formula:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skor Operasional = (Pencapaian Target × 50%) + (Skor Kebersihan × 30%) + (Kepatuhan SOP × 20%)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Skor</th><th>Label</th></tr></thead><tbody><tr><td>≥ 85</td><td>EXCELLENT</td></tr><tr><td>≥ 70</td><td>GOOD</td></tr><tr><td>≥ 50</td><td>ATTENTION</td></tr><tr><td>&lt; 50</td><td>CRITICAL</td></tr></tbody></table><hr>',25)])])}const k=t(d,[["render",i]]);export{m as __pageData,k as default};
